// ── Normalize both payload types ──────────────────────────────────────
// type: 'assessment' → from Send My Results (full assessment data)
// type: 'click'      → from Talk to Advisor / Chat widget / Call button

const body       = $input.first().json.body ?? $input.first().json;
const type       = body.type        ?? 'click';
const lead       = body.lead        ?? {};
const assessment = body.assessment  ?? {};
const attribution= body.attribution ?? {};
const email      = body.email       ?? {};

// Sanitize agent name to valid sheet tab name (max 100 chars, safe chars only)
const rawAgent = (attribution.agent ?? 'direct').toString().trim();
const agentTab = (rawAgent === '' ? 'direct' : rawAgent)
  .replace(/[\[\]\*\?\/\\:]/g, '_')
  .slice(0, 100);

// Flatten arrays → pipe-separated strings
const gaps = Array.isArray(assessment.gaps)
  ? assessment.gaps.filter(Boolean).join(' | ')
  : (assessment.gaps ?? '');

const recommendations = Array.isArray(assessment.recommendations)
  ? assessment.recommendations.map(r => r.name ?? r).filter(Boolean).join(' | ')
  : '';

const gapCount = Array.isArray(assessment.gaps)
  ? assessment.gaps.filter(Boolean).length
  : 0;

// Human-readable source label
const source = (() => {
  if (type === 'assessment') return 'Assessment Form';
  const s = (body.source ?? '').toLowerCase();
  if (s.includes('chat_launcher')) return 'Chat Widget';
  if (s.includes('advisor_btn'))   return 'Talk to Advisor';
  if (s.includes('call_btn'))      return 'Call Button';
  return body.source ?? 'Unknown';
})();

// ── Output field names MUST match Google Sheet column headers exactly ──
return [{
  json: {
    timestamp:       body.timestamp ?? new Date().toISOString(),
    name:            lead.name        ?? '',
    contactType:     lead.contactType ?? '',
    contact:         lead.contact     ?? '',
    score:           assessment.score       ?? '',
    statusLabel:     assessment.statusLabel ?? '',
    riskLevel:       assessment.riskLevel   ?? '',
    gapCount,
    gaps,
    source,
    Agent:           attribution.agent     ?? 'direct',
    'UTM Source':    attribution.utmSource ?? 'direct',
    'UTM Medium':    attribution.utmMedium ?? 'organic',
    type,
    message:         lead.message  ?? '',
    platform:        lead.platform ?? '',
    recommendations,
    // ── Internal routing — NOT written to sheet ──
    _agentTab:      agentTab,
    _spreadsheetId: '1gEa5mu9d4ZHZBX_oi1eSKbzoG9tlyJKh-uNFaUCYxzQ',
  }
}];

// Check if a tab named after the agent already exists
const prepData  = $('Prepare Data').first().json;
const agentTab  = prepData._agentTab;
const sheetMeta = $input.first().json;
const sheets    = sheetMeta.sheets ?? [];

const tabExists = sheets.some(
  s => (s.properties?.title ?? '').toLowerCase() === agentTab.toLowerCase()
);

// Pass through all prep data + routing flags
return [{ json: { ...prepData, tabExists } }];

// After tab creation (or if it already existed), pass data through cleanly
// Remove internal routing fields before writing to sheet
const d = $('Check Tab Exists').first().json;
const { _agentTab, _spreadsheetId, tabExists, ...sheetRow } = d;
return [{ json: { ...sheetRow, _agentTab, _spreadsheetId } }];
